import{G as r,c as a,b as l,ae as t,M as o,f as i}from"./chunks/framework.Cpb2nuHT.js";const g=JSON.parse('{"title":"乐观锁和悲观锁","description":"","frontmatter":{"title":"乐观锁和悲观锁","date":"2024/7/30","tags":["乐观锁","悲观锁","Java"],"author":"花木凋零成兰"},"headers":[],"relativePath":"MisNotes/乐观锁和悲观锁.md","filePath":"MisNotes/乐观锁和悲观锁.md","lastUpdated":1722497451000}'),n={name:"MisNotes/乐观锁和悲观锁.md"},s={class:"MathJax",jax:"SVG",style:{direction:"ltr",position:"relative"}},d={style:{overflow:"visible","min-height":"1px","min-width":"1px","vertical-align":"-0.186ex"},xmlns:"http://www.w3.org/2000/svg",width:"6.485ex",height:"1.731ex",role:"img",focusable:"false",viewBox:"0 -683 2866.6 765","aria-hidden":"true"};function p(c,e,Q,h,u,m){return l(),a("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1722297600000"},[e[4]||(e[4]=t('<h1 id="乐观锁和悲观锁" tabindex="-1">乐观锁和悲观锁 <a class="header-anchor" href="#乐观锁和悲观锁" aria-label="Permalink to &quot;乐观锁和悲观锁&quot;">​</a></h1><h2 id="悲观锁" tabindex="-1">悲观锁 <a class="header-anchor" href="#悲观锁" aria-label="Permalink to &quot;悲观锁&quot;">​</a></h2><p>悲观锁总是假设<strong>最坏</strong>的情况, 认为共享资源每次被访问时都会出现问题(比如共享资源被修改), 所以需要在每次获取资源操作时上锁, 如此避免其他线程的访问, 其他线程想拿到该资源时会被阻塞, 直到锁被释放;</p><p>即, <strong>共享资源每次只有一个线程使用, 其他线程阻塞, 使用结束后再被其他线程访问</strong>;</p><p>在 Java 中 <code>synchronized</code> 和 <code>ReentrantLock</code>(可重入锁) 等独占锁就是悲观锁思想的体现;</p><p><strong>缺点:</strong></p><ul><li>高并发的场景下, 激烈地锁竞争容易造成线程阻塞, 同时大量阻塞线程会导致系统的上下文切换频繁, 增加性能开销;</li><li>线程获取锁的顺序不当时, 可能会造成死锁问题;</li></ul><h2 id="乐观锁" tabindex="-1">乐观锁 <a class="header-anchor" href="#乐观锁" aria-label="Permalink to &quot;乐观锁&quot;">​</a></h2><p>乐观锁则总是假设<strong>最好</strong>的情况, 认为共享资源每次被访问的时候不会出现问题, 线程可以不停地执行, 不需要加锁或等待, 只有在提交修改时对资源进行验证, 即判断是否被其他线程修改;</p><p>乐观锁一般会使用版本号机制或 CAS 算法实现, CAS算法居多;</p><p>在 Java 中 <code>java.util.concurrent.atomic</code> 包下的原子变量类就是使用乐观锁的一种实现方式 CAS 实现的; 且 <code>LongAdder</code> 在高并发的情况下会比 <code>AtomicInteger</code> 和 <code>AtomicLong</code> 性能更好, 代价是消耗更多的内存空间;</p><p><strong>优点:</strong></p><ul><li>高并发场景下, 乐观锁相对悲观锁而言, 不存在锁竞争造成线程阻塞, 也不会有死锁问题; 性能上往往更好;</li></ul><p><strong>缺点:</strong></p><ul><li>冲突频繁发生, 即写操作占比更多, 会导致频繁失败重试, 此时对性能影响较大, CPU飙升; 可以采用空间换空间的方式解决该问题, 如<code>LongAdder</code>;</li></ul><h3 id="版本号机制" tabindex="-1">版本号机制 <a class="header-anchor" href="#版本号机制" aria-label="Permalink to &quot;版本号机制&quot;">​</a></h3><blockquote><p>一般是在数据表中添加 数据版本号<code>version</code>字段, 表示数据被修改次数;</p></blockquote><p>当数据被修改时, <code>version</code>会加一; 如线程A更新数据值时, 在读取数据的同时也会读取 <code>version</code>的值, 提交更新时, 若刚读取到的 <code>version</code> 值等于当前数据库中的 <code>version</code> 值时才会更新; 否则重试更新操作, 直到更新成功;</p><p><strong>示例：</strong></p><blockquote><p>假设银行账号信息表中有一个 version 字段, 值为1, 且账户余额 <code>balance</code> 值为 $500;</p></blockquote><ol><li>线程A此时读取数据(version = 1), 并扣除余额 $50(此时 balance = 450);</li><li>在线程A执行的过程中, 线程B 也读取了数据(version = 1), 并扣除余额 $20(此时 balance = 480);</li><li>线程A 执行更新操作后, 提交数据(version=1, balance=450)更新, 此时提交数据版本(version=1)等于数据库中记录的当前版本(version=1); 数据成功更新, 且数据记录版本version值为2;</li><li>当线程B完成数据更新操作后, 提交更新时(version=1, balance=480), 此时数据库中数据记录版本为 <strong>2</strong>, 则不满足&quot;提交版本必须等于当前版本才能更新&quot;的乐观锁策略, 因此,线程B的提交被驳回;</li></ol><p>如此, 则避免了线程B基于<code>version=1</code>的旧版本数据修改的结果覆盖线程A的操作结果的可能;</p><h3 id="cas算法" tabindex="-1">CAS算法 <a class="header-anchor" href="#cas算法" aria-label="Permalink to &quot;CAS算法&quot;">​</a></h3><blockquote><p>CAS 全称是 Compare And Swap(比较和交换), 用于实现乐观锁, 被广泛应用于各大框架中;</p></blockquote><p>CAS 的思想就是: 用一个预期值和要更新的变量值进行比较, 两值相等才会进行更新;</p><p>CAS 是一个原子操作, 底层依赖于一条 CPU 的原子指令;</p><p>CAS 涉及三个操作数:</p><ul><li>V: 要更新的变量值(Var);</li><li>E: 预期值(Excepted);</li><li>N: 拟写入的新值(New);</li></ul>',28)),o("p",null,[e[2]||(e[2]=i("即当且仅当 ",-1)),o("mjx-container",s,[(l(),a("svg",d,[...e[0]||(e[0]=[t('<g stroke="currentColor" fill="currentColor" stroke-width="0" transform="scale(1,-1)"><g data-mml-node="math"><g data-mml-node="mi"><path data-c="1D449" d="M52 648Q52 670 65 683H76Q118 680 181 680Q299 680 320 683H330Q336 677 336 674T334 656Q329 641 325 637H304Q282 635 274 635Q245 630 242 620Q242 618 271 369T301 118L374 235Q447 352 520 471T595 594Q599 601 599 609Q599 633 555 637Q537 637 537 648Q537 649 539 661Q542 675 545 679T558 683Q560 683 570 683T604 682T668 681Q737 681 755 683H762Q769 676 769 672Q769 655 760 640Q757 637 743 637Q730 636 719 635T698 630T682 623T670 615T660 608T652 599T645 592L452 282Q272 -9 266 -16Q263 -18 259 -21L241 -22H234Q216 -22 216 -15Q213 -9 177 305Q139 623 138 626Q133 637 76 637H59Q52 642 52 648Z" style="stroke-width:3;"></path></g><g data-mml-node="mo" transform="translate(1046.8,0)"><path data-c="3D" d="M56 347Q56 360 70 367H707Q722 359 722 347Q722 336 708 328L390 327H72Q56 332 56 347ZM56 153Q56 168 72 173H708Q722 163 722 153Q722 140 707 133H70Q56 140 56 153Z" style="stroke-width:3;"></path></g><g data-mml-node="mi" transform="translate(2102.6,0)"><path data-c="1D438" d="M492 213Q472 213 472 226Q472 230 477 250T482 285Q482 316 461 323T364 330H312Q311 328 277 192T243 52Q243 48 254 48T334 46Q428 46 458 48T518 61Q567 77 599 117T670 248Q680 270 683 272Q690 274 698 274Q718 274 718 261Q613 7 608 2Q605 0 322 0H133Q31 0 31 11Q31 13 34 25Q38 41 42 43T65 46Q92 46 125 49Q139 52 144 61Q146 66 215 342T285 622Q285 629 281 629Q273 632 228 634H197Q191 640 191 642T193 659Q197 676 203 680H757Q764 676 764 669Q764 664 751 557T737 447Q735 440 717 440H705Q698 445 698 453L701 476Q704 500 704 528Q704 558 697 578T678 609T643 625T596 632T532 634H485Q397 633 392 631Q388 629 386 622Q385 619 355 499T324 377Q347 376 372 376H398Q464 376 489 391T534 472Q538 488 540 490T557 493Q562 493 565 493T570 492T572 491T574 487T577 483L544 351Q511 218 508 216Q505 213 492 213Z" style="stroke-width:3;"></path></g></g></g>',1)])])),e[1]||(e[1]=o("mjx-assistive-mml",{unselectable:"on",display:"inline",style:{top:"0px",left:"0px",clip:"rect(1px, 1px, 1px, 1px)","-webkit-touch-callout":"none","-webkit-user-select":"none","-khtml-user-select":"none","-moz-user-select":"none","-ms-user-select":"none","user-select":"none",position:"absolute",padding:"1px 0px 0px 0px",border:"0px",display:"block",width:"auto",overflow:"hidden"}},[o("math",{xmlns:"http://www.w3.org/1998/Math/MathML"},[o("mi",null,"V"),o("mo",null,"="),o("mi",null,"E")])],-1))]),e[3]||(e[3]=i(" 时, CAS 通过原子方式用 新值N 来更新V的值; 如果不等, 则说明已经有其他线程更新了 V, 当前线程放弃更新;",-1))]),e[5]||(e[5]=t('<p><strong>示例：</strong></p><blockquote><p>线程 A 要修改变量 i 的值为6, i 原值为 1(V = 1, E = 1, N = 6, 假设不存在 ABA 问题);</p></blockquote><ol><li>i 与 1 进行比较, 如果相等, 则说明线程没有被修改, 可以设置为6;</li><li>i 与 1 进行比较, 如果不相等, 则说明线程被其他线程修改, 当前线程放弃更新, CAS 操作失败;</li></ol><p>当多个线程同时使用 CAS 操作一个变量时, 只有一个可以成功更新, 其余均会失败, 但失败的线程并不会被挂起, 仅仅只是被告知失败, 并允许再次尝试, 当然也允许失败的线程放弃操作;</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>悲观锁多用于写比较多的情况 (多写场景,竞争激烈), 可以避免频繁失败和重试影响性能; 因为悲观锁开销是固定的; 如果乐观锁解决了频繁重试(使用 LongAdder)的问题, 也可以考虑使用乐观锁;</p><p>乐观锁多用于写比较少的情况 (多读场景,竞争较少), 可以避免频繁加锁影响性能; 但是,乐观锁主要针对的对象是单个共享变量;</p><h2 id="参考文章" tabindex="-1">参考文章 <a class="header-anchor" href="#参考文章" aria-label="Permalink to &quot;参考文章&quot;">​</a></h2><ul><li><a href="https://javaguide.cn/java/concurrent/optimistic-lock-and-pessimistic-lock.html" target="_blank" rel="noreferrer">乐观锁和悲观锁详解</a></li></ul>',9))])}const _=r(n,[["render",p]]);export{g as __pageData,_ as default};
